={{ (() => {
  const cfg = $items('CONFIG INICIAL', 0, 0)[0].json.cfg;
  const offset = cfg.runtime.timeOffsetMinutes || 0;
  const nowOffset = `now() + interval '${offset} minutes'`;
  const tz = cfg.policyPreventiva.TZ;
  const modo = cfg.prioridad.modo || 'NORMAL';
  const dias = cfg.prioridad.modo1_dias || [];
  const ops = cfg.prioridad.modo2_operaciones || [];

  const modo1DiasSQL = dias.length > 0 
    ? `c.dias_retraso::int IN (${dias.map(d => parseInt(d)).filter(d => !isNaN(d)).join(',')})`
    : 'FALSE';
  const modo2OpsSQL = ops.length > 0
    ? `c.num_operacion IN (${ops.map(o => "'" + String(o).replace(/'/g, "''") + "'").join(',')})`
    : 'FALSE';
  const modo3Activo = cfg.prioridad.modo3_activo !== false;
  const modo3Desde = (cfg.prioridad.modo3_fecha_desde || '2026-04-01').replace(/'/g, "''");
  const modo3Hasta = (cfg.prioridad.modo3_fecha_hasta || '2026-04-30').replace(/'/g, "''");
  const modo3FechaSQL = `c.fecha_vencimiento BETWEEN '${modo3Desde}' AND '${modo3Hasta}'`;

  let priorityOrder = '';

  if (modo === 'MODO1') {
    priorityOrder = `CASE WHEN ${modo1DiasSQL} THEN 0 ELSE 1 END,`;
  } else if (modo === 'MODO2') {
    priorityOrder = `CASE WHEN ${modo2OpsSQL} THEN 0 ELSE 1 END,`;
  } else if (modo === 'AUTO') {
    priorityOrder = `CASE WHEN ${modo1DiasSQL} THEN 0 WHEN ${modo2OpsSQL} THEN 1 WHEN ${modo3Activo ? modo3FechaSQL : 'FALSE'} THEN 2 ELSE 3 END,`;
  } else if (modo === 'MODO3') {
    priorityOrder = `CASE WHEN ${modo3Activo ? modo3FechaSQL : 'FALSE'} THEN 0 ELSE 1 END,`;
  }

  let finalizadoDias = `c.dias_retraso::int <= 0`;
  if (modo === 'MODO1' || modo === 'AUTO' || modo === 'MODO3') {
    if (modo === 'MODO3') {
      finalizadoDias = `(c.dias_retraso::int <= 0 OR ${modo3Activo ? modo3FechaSQL : 'FALSE'})`;
    } else {
      finalizadoDias = `(c.dias_retraso::int <= 0 OR ${modo1DiasSQL})`;
    }
  }
  let finalizadoFecha = `c.fecha_vencimiento = timezone('${tz}', ${nowOffset})::date`;
  if (modo === 'MODO1' || modo === 'AUTO' || modo === 'MODO3') {
    if (modo === 'MODO3') {
      finalizadoFecha = `(c.fecha_vencimiento = timezone('${tz}', ${nowOffset})::date OR ${modo3Activo ? modo3FechaSQL : 'FALSE'})`;
    } else {
      finalizadoFecha = `(c.fecha_vencimiento = timezone('${tz}', ${nowOffset})::date OR ${modo1DiasSQL})`;
    }
  }

  return `
    WITH next_call AS (
      SELECT c.num_operacion, timezone('${tz}', ${nowOffset}) as now_local
      FROM ${cfg.db.schema}.${cfg.db.table} c
      WHERE (
              c.estado_flujo IN ('${cfg.states.pending}', '${cfg.states.retry}')
              AND (c.fecha_reagenda IS NULL OR c.fecha_reagenda <= ${nowOffset})
            )
         OR (
              c.estado_flujo = 'EN_PROCESO'
              AND (c.fecha_reagenda IS NULL OR c.fecha_reagenda <= ${nowOffset})
            )
         OR (
              c.estado_flujo = '${cfg.states.done}'
              AND ${finalizadoFecha}
              AND c.telefono_preferido IS NOT NULL
              AND ${finalizadoDias}
            )
      ORDER BY 
        ${priorityOrder}
        CASE WHEN c.estado_flujo = '${cfg.states.done}' THEN 0 ELSE 1 END,
        c.intentos_llamada ASC, 
        c.fecha_reagenda ASC NULLS FIRST
      LIMIT 1
      FOR UPDATE SKIP LOCKED
    )
    UPDATE ${cfg.db.schema}.${cfg.db.table} c
    SET estado_flujo = '${cfg.states.inProgress}',
        updated_at = ${nowOffset}
    FROM next_call nc
    WHERE c.num_operacion = nc.num_operacion
    RETURNING c.*;
  `;
})() }}

