return items.map(item => {
  const lead = item.json;
  const cfg = $items('CONFIG INICIAL', 0, 0)[0].json.cfg;

  lead.system_payload = cfg.policy;
  lead.num_operacion = String(lead.num_operacion ?? '').trim();
  lead.nombre_completo = lead.nombre_completo || `${lead.nombre ?? ''} ${lead.apellido ?? ''}`.trim();
  lead.intentos_llamada = Number(lead.intentos_llamada || 0);
  lead.win_tries = Number(lead.win_tries || 0);
  lead.telefono_index = Number(lead.telefono_index ?? 0);
  lead.monto = Number(lead.monto ?? lead.valor ?? 0);
  lead.fecha_vencimiento = lead.fecha_vencimiento || lead.fecha_maxima || null;

  return item;
});

function parseTime(timeStr, tz) {
  const now = DateTime.now().setZone(tz);
  const [h, m] = timeStr.split(':').map(Number);
  return now.set({ hour: h, minute: m, second: 0, millisecond: 0 });
}

function findPhoneRule(reason, rules, defaultRule) {
  if (!reason) return defaultRule;
  for (const key in rules) {
    if (key.endsWith('-') && reason.startsWith(key)) return rules[key];
    if (reason === key) return rules[key];
  }
  return defaultRule;
}

return items.map(item => {
  const cfg = $items('CONFIG INICIAL', 0, 0)[0].json.cfg;
  const db = item.json || {};
  let out = { ...db };

  const now = DateTime.now().setZone(cfg.policyPreventiva.TZ).plus({ minutes: cfg.runtime.timeOffsetMinutes || 0 });
  const dow = now.weekday; // 1=Mon, 7=Sun
  const todayIso = now.toFormat('yyyy-MM-dd');

  const isFeriado = cfg.calendar.feriados.includes(todayIso);
  out.modo_operativo = (dow === 6 || isFeriado) ? 'informativo' : 'normal';

  const diasRaw = String(db.dias_retraso || '0').trim();
  let diasNum = Number(diasRaw.replace('+', ''));
  if (isNaN(diasNum)) diasNum = 0;

  if (diasRaw.includes('+') || diasRaw.includes('-')) {
    out.agente_tipo = diasNum < 0 ? 'PREVENTIVA' : 'COBROS';
  } else {
    const fVenc = db.fecha_vencimiento ? DateTime.fromISO(db.fecha_vencimiento.substring(0, 10)).setZone(cfg.policyPreventiva.TZ) : now;
    out.agente_tipo = (now <= fVenc) ? 'PREVENTIVA' : 'COBROS';
  }

  out.assistant_id = out.agente_tipo === 'PREVENTIVA' ? cfg.agents.PREVENTIVA : cfg.agents.COBROS;

  const intentosRaw = Number(db.intentos_llamada) || 0;
  const winTriesRaw = Number(db.win_tries) || 0;
  const winStamp = String(db.win_stamp || '');

  out.intentos_llamada = intentosRaw;
  out.win_tries = winTriesRaw;
  out.win_stamp = winStamp;
  out.puedeLlamar = false;
  out.estado_flujo = db.estado_flujo || cfg.states.pending;

  if (dow === 7) {
    out.puedeLlamar = false;
    out.estado_flujo = cfg.states.retry;
    out.reintentar_iso = now.plus({ days: 1 }).set({ hour: 8, minute: 0, second: 0 }).toUTC().toISO();
    out.observacion_politica = 'Domingo no se marca';
    return { json: out };
  }

  // ==== LOGICA PREVENTIVA ====
  if (out.agente_tipo === 'PREVENTIVA') {
    const pol = cfg.policyPreventiva;
    if (intentosRaw >= pol.maxLifetimeTries) {
      out.estado_flujo = cfg.states.done;
      out.observacion_politica = 'Max lifetime tries alcanzado (PREVENTIVA)';
      return { json: out };
    }

    let activeWin = null;
    let nextWin = null;
    let minWaitMs = Infinity;

    for (const w of pol.windows) {
      const days = w.days.split(',').map(Number);
      if (!days.includes(dow)) continue;
      const st = parseTime(w.start, pol.TZ);
      const en = parseTime(w.end, pol.TZ);
      if (now >= st && now <= en) { activeWin = w; break; }
      if (st > now) {
        const wait = st.diff(now).toMillis();
        if (wait < minWaitMs) { minWaitMs = wait; nextWin = w; }
      }
    }

    if (!activeWin) {
      out.estado_flujo = cfg.states.retry;
      if (nextWin) out.reintentar_iso = parseTime(nextWin.start, pol.TZ).toUTC().toISO();
      else out.reintentar_iso = now.plus({ days: dow === 6 ? 2 : 1 }).set({ hour: 8, minute: 0, second: 0 }).toUTC().toISO();
      return { json: out };
    }

    const curStamp = `${todayIso}:${activeWin.id}`;
    if (winStamp !== curStamp) { out.win_stamp = curStamp; out.win_tries = 0; }

    if (out.win_tries >= activeWin.max) {
      out.estado_flujo = cfg.states.retry;
      if (nextWin) out.reintentar_iso = parseTime(nextWin.start, pol.TZ).toUTC().toISO();
      else out.reintentar_iso = now.plus({ days: dow === 6 ? 2 : 1 }).set({ hour: 8, minute: 0, second: 0 }).toUTC().toISO();
      return { json: out };
    }

    out.puedeLlamar = true;
    out.estado_flujo = cfg.states.inProgress;
    out.activeWinPhones = activeWin.phones;
    return { json: out };
  }

  // ==== LOGICA COBROS (2 FASES) ====
  const pol = cfg.policyCobros;
  if (intentosRaw >= pol.maxLifetimeTries) {
    out.estado_flujo = cfg.states.done;
    return { json: out };
  }

  const phase = intentosRaw < pol.phaseThreshold ? 1 : 2;
  const phaseConfig = phase === 1 ? pol.phase1 : pol.phase2;
  const phaseAttempts = phase === 1 ? intentosRaw : intentosRaw - pol.phaseThreshold;

  if (phase === 2 && phaseAttempts === 0 && !winStamp.startsWith('P2:')) {
    out.puedeLlamar = false;
    out.estado_flujo = cfg.states.retry;

    let nextWinSt = null;
    let minWaitMs = Infinity;

    for (const w of pol.phase2.windows) {
      const days = w.days.split(',').map(Number);
      if (!days.includes(dow)) continue;
      const st = parseTime(w.start, pol.TZ);
      if (st > now) {
        const wait = st.diff(now).toMillis();
        if (wait < minWaitMs) { minWaitMs = wait; nextWinSt = st; }
      }
    }

    const baseRecall = now.plus({ minutes: pol.recallBetweenPhases });
    if (nextWinSt && nextWinSt > baseRecall) out.reintentar_iso = nextWinSt.toUTC().toISO();
    else if (nextWinSt && nextWinSt <= baseRecall) out.reintentar_iso = baseRecall.toUTC().toISO();
    else {
      out.reintentar_iso = now.plus({ days: dow === 6 ? 2 : 1 }).set({ hour: 8, minute: 0, second: 0 }).toUTC().toISO();
      const m = DateTime.fromISO(out.reintentar_iso);
      if (baseRecall > m) out.reintentar_iso = baseRecall.toUTC().toISO();
    }

    out.telefono_index = 0;
    out.win_tries = 0;
    return { json: out };
  }

  let activeWin = null;
  let nextWin = null;
  let minWaitMs = Infinity;

  for (const w of phaseConfig.windows) {
    const days = w.days.split(',').map(Number);
    if (!days.includes(dow)) continue;
    const st = parseTime(w.start, pol.TZ);
    const en = parseTime(w.end, pol.TZ);
    if (now >= st && now <= en) { activeWin = w; break; }
    if (st > now) {
      const wait = st.diff(now).toMillis();
      if (wait < minWaitMs) { minWaitMs = wait; nextWin = w; }
    }
  }

  if (!activeWin) {
    out.estado_flujo = cfg.states.retry;
    if (nextWin) out.reintentar_iso = parseTime(nextWin.start, pol.TZ).toUTC().toISO();
    else out.reintentar_iso = now.plus({ days: dow === 6 ? 2 : 1 }).set({ hour: 8, minute: 0, second: 0 }).toUTC().toISO();
    return { json: out };
  }

  const curStamp = `P${phase}:${todayIso}:${activeWin.id}`;
  if (winStamp !== curStamp) out.win_stamp = curStamp;

  const lastRes = String(db.ultimo_resultado_llamada || '').toLowerCase();
  const rule = findPhoneRule(lastRes, pol.phoneRules, pol.phoneRuleDefault);

  if (out.win_tries >= rule.maxRetries || rule.advancePhone) {
    const phonesArr = activeWin.phones.split(',');
    out.telefono_index = ((Number(db.telefono_index) || 0) + 1) % phonesArr.length;
    out.win_tries = 0;
  }

  out.puedeLlamar = true;
  out.estado_flujo = cfg.states.inProgress;
  out.activeWinPhones = activeWin.phones;
  return { json: out };
});

return items.map(item => {
  const db = item.json || {};
  let phones = [];
  const cfg = $items('CONFIG INICIAL', 0, 0)[0].json.cfg;
  const CC = cfg.policyPreventiva.CC || '+593';
  const allowedStr = String(item.json.activeWinPhones || cfg.phoneFields.join(','));
  const phoneFields = allowedStr.split(',');

  for (const field of phoneFields) {
    const val = String(db[field] || '').replace(/\D/g, '');
    if (val.length >= 9) {
      let e164 = val;
      if (val.startsWith('0')) e164 = CC + val.substring(1);
      else if (!val.startsWith('+')) e164 = CC + val;
      if (!phones.find(p => p.e164 === e164)) phones.push({ field, e164 });
    }
  }

  let selected = null;
  const tIndex = Number(item.json.telefono_index || db.telefono_index || 0);

  if (phones.length > 0) {
    if (item.json.agente_tipo === 'COBROS') {
      const idx = tIndex % phones.length;
      selected = phones[idx];
    } else {
      const effIdx = Math.min(tIndex, phones.length - 1);
      selected = phones[effIdx];
    }
  }

  item.json.phones_parsed = phones;
  item.json.selected_phone = selected;
  item.json.telefono_actual = selected ? selected.e164 : '';
  return item;
});

return items.map(item => {
  const lead = item.json;
  const cfg = $items('CONFIG INICIAL', 0, 0)[0].json.cfg;
  const fallback = cfg.noPhoneClassification;

  if (lead.hasPhonesOutsideWindow) {
    const t = new Date();
    t.setMinutes(t.getMinutes() + Number(cfg.policy.offHoursWait || 30));
    lead.estado_flujo = cfg.states.retry;
    lead.status_sugerido = 'REINTENTAR';
    lead.fecha_reagenda = t.toISOString();
    lead.reintentar_iso = lead.fecha_reagenda;
    return item;
  }

  lead.estado_flujo = cfg.states.done;
  lead.status_sugerido = 'FINAL';
  lead.fecha_reagenda = null;
  lead.nomenclatura = fallback.nomenclatura;
  lead.codigo_respuesta = fallback.codigo_respuesta;
  lead.motivo = fallback.motivo;
  return item;
});

parameters.query:
={{ (() => {
  const cfg = $items('CONFIG INICIAL', 0, 0)[0].json.cfg;
  const raw = String($json.num_operacion ?? $items('BUSCA Y MARCA COMO EN PROCESO1', 0, 0)[0].json.num_operacion ?? '').trim();
  if (!raw) return `SELECT 'skip_fallback_sin_num_operacion' AS status`;

  const numOperacion = raw.replace(/'/g, "''");

  const hasSnapshot = [
    $json.snapshot_estado_flujo,
    $json.snapshot_fecha_reagenda,
    $json.snapshot_intentos_llamada,
    $json.snapshot_win_tries,
    $json.snapshot_telefono_index,
    $json.snapshot_win_stamp,
    $json.snapshot_fecha_ultima_llamada,
    $json.snapshot_telefono_preferido,
    $json.snapshot_fecha_promesa,
    $json.snapshot_monto_promesa,
  ].some(v => v !== undefined);

  if (hasSnapshot) {
    const snapEstado = String($json.snapshot_estado_flujo ?? cfg.states.pending ?? 'PENDIENTE').replace(/'/g, "''");

    const snapFechaReagendaRaw = $json.snapshot_fecha_reagenda;
    const snapFechaReagendaSql = (snapFechaReagendaRaw == null || String(snapFechaReagendaRaw).trim() === '')
      ? 'NULL'
      : ` '${String(snapFechaReagendaRaw).replace(/'/g, "''")}'::timestamptz `;

    const snapFechaUltRaw = $json.snapshot_fecha_ultima_llamada;
    const snapFechaUltSql = (snapFechaUltRaw == null || String(snapFechaUltRaw).trim() === '')
      ? 'NULL'
      : ` '${String(snapFechaUltRaw).replace(/'/g, "''")}'::timestamptz `;

    const snapTelPrefRaw = $json.snapshot_telefono_preferido;
    const snapTelPrefSql = (snapTelPrefRaw == null || String(snapTelPrefRaw).trim() === '')
      ? 'NULL'
      : ` '${String(snapTelPrefRaw).replace(/'/g, "''")}' `;

    const snapFechaPromRaw = $json.snapshot_fecha_promesa;
    const snapFechaPromSql = (snapFechaPromRaw == null || String(snapFechaPromRaw).trim() === '')
      ? 'NULL'
      : ` '${String(snapFechaPromRaw).replace(/'/g, "''")}'::date `;

    const snapMontoPromNum = Number($json.snapshot_monto_promesa);
    const snapMontoPromSql = Number.isFinite(snapMontoPromNum) ? String(snapMontoPromNum) : 'NULL';

    const snapIntentos = Number($json.snapshot_intentos_llamada ?? 0);
    const snapWinTries = Number($json.snapshot_win_tries ?? 0);
    const snapTelIdx = Number($json.snapshot_telefono_index ?? 0);

    const snapWinStampRaw = $json.snapshot_win_stamp;
    const snapWinStampSql = (snapWinStampRaw == null || String(snapWinStampRaw).trim() === '')
      ? 'NULL'
      : ` '${String(snapWinStampRaw).replace(/'/g, "''")}' `;

    return `UPDATE ${cfg.db.schema}.${cfg.db.table}
            SET estado_flujo = '${snapEstado}',
                fecha_reagenda = ${snapFechaReagendaSql},
                intentos_llamada = ${Number.isFinite(snapIntentos) ? snapIntentos : 0},
                win_tries = ${Number.isFinite(snapWinTries) ? snapWinTries : 0},
                telefono_index = ${Number.isFinite(snapTelIdx) ? snapTelIdx : 0},
                win_stamp = ${snapWinStampSql},
                fecha_ultima_llamada = ${snapFechaUltSql},
                telefono_preferido = ${snapTelPrefSql},
                fecha_promesa = ${snapFechaPromSql},
                monto_promesa = ${snapMontoPromSql},
                updated_at = NOW()
            WHERE num_operacion = '${numOperacion}'
            RETURNING num_operacion, 'restored_from_snapshot' AS status;`;
  }

  const estado = String($json.estado_flujo || cfg.states.retry || 'REINTENTAR').replace(/'/g, "''");
  const fechaRaw = $json.reintentar_iso || $json.fecha_reagenda || null;
  const fechaSql = (fechaRaw == null || String(fechaRaw).trim() === '')
    ? `NOW() + INTERVAL '30 minutes'`
    : ` '${String(fechaRaw).replace(/'/g, "''")}'::timestamptz `;

  const intentos = Number($json.intentos_llamada || 0);
  const winTries = Number($json.win_tries || 0);
  const telIdx = Number($json.telefono_index || 0);

  return `UPDATE ${cfg.db.schema}.${cfg.db.table}
          SET estado_flujo = '${estado}',
              fecha_reagenda = ${fechaSql},
              intentos_llamada = ${Number.isFinite(intentos) ? intentos : 0},
              win_tries = ${Number.isFinite(winTries) ? winTries : 0},
              telefono_index = ${Number.isFinite(telIdx) ? telIdx : 0},
              updated_at = NOW()
          WHERE num_operacion = '${numOperacion}'
          RETURNING num_operacion, 'fallback_without_snapshot' AS status;`;
})() }}
